     8→import Dependencies
     9→import Foundation
    10→
    11→final class UserDefaultsClient {
    12→    
    13→    @propertyWrapper
    14→    private struct UserDefault<T: Codable> {
    15→        let key: String
    16→        let userDefaults: UserDefaults
    17→        
    18→        init(
    19→            key: String,
    20→            userDefaults: UserDefaults = .standard
    21→        ) {
    22→            self.key = key
    23→            self.userDefaults = userDefaults
    24→        }
    25→        
    26→        var wrappedValue: T? {
    27→            get {
    28→                if let savedData = userDefaults.object(forKey: key) as? Data {
    29→                    if let decodedObject = try? JSONDecoder().decode(T.self, from: savedData) {
    30→                        return decodedObject
    31→                    }
    32→                }
    33→                
    34→                return nil
    35→            }
    36→            set {
    37→                if let encodedData = try? JSONEncoder().encode(newValue) {
    38→                    userDefaults.set(encodedData, forKey: key)
    39→                }
    40→            }
    41→        }
    42→    }
    43→    
    44→    @UserDefault(key: "guideRequired")
    45→    private var appGuideRequired: Bool?
    46→    
    47→    var guideRequired: Bool {
    48→        return appGuideRequired ?? true
    49→    }
    50→    
    51→    func setGuideCompleted() {
    52→        appGuideRequired = false
    53→    }
    54→    
    55→    @UserDefault(key: "timer")
    56→    private var timer: TimerEntity?
    57→    
    58→    func getTimer() -> TimerEntity? {
    59→        return timer
    60→    }
    61→    
    62→    func setTimer(_ newTimer: TimerEntity) {
    63→        timer = newTimer
    64→    }
    65→    
    66→    func removeTimer() {
    67→        timer = nil
    68→    }
    69→
    70→    @UserDefault(key: "settingSliderScale") // 앱 설정 슬라이드값
    71→    private var settingSliderScale: [SettingType: Float]?
    72→
    73→    func getSettingSliderScale(for type: SettingType) -> Float {
    74→        return settingSliderScale?[type] ?? 0.5
    75→    }
    76→
    77→    func setSettingSliderScale(for type: SettingType, value: Float) {
    78→        if settingSliderScale == nil {
    79→            settingSliderScale = [:]
    80→        }
    81→
    82→        settingSliderScale?[type] = value
    83→    }
    84→
    85→    @UserDefault(key: "settingToggleValue") // 앱 설정 토글 값
    86→    private var settingToggleValue: [SettingType: Bool]?
    87→
    88→    func isSettingToggleOn(for type: SettingType) -> Bool {
    89→        return settingToggleValue?[type] ?? true
    90→    }
    91→
    92→    func setSettingToggle(for type: SettingType, to value: Bool) {
    93→        if settingToggleValue == nil {
    94→            settingToggleValue = [:]
    95→        }
    96→
    97→        settingToggleValue?[type] = value
    98→    }
    99→
   100→    @UserDefault(key: "useTooltip") // 툴팁 노출 여부
   101→    private var useTooltip: [TooltipType: Bool]?
   102→
   103→    func canUseTooltip(for type: TooltipType) -> Bool {
   104→        return useTooltip?[type] ?? true
   105→    }
   106→
   107→    func setCanUseTooltip(for type: TooltipType, _ newValue: Bool) {
   108→        if useTooltip == nil {
   109→            useTooltip = [:]
   110→        }
   111→
   112→        useTooltip?[type] = newValue
   113→    }
   114→
   115→    @UserDefault(key: "needsOnboarding") // 앱 설정 토글 값
   116→    private var onboardingRequired: Bool?
   117→
   118→    func needsOnboarding() -> Bool {
   119→        return onboardingRequired ?? true
   120→    }
   121→
   122→    func setOnboardingCompleted() {
   123→        onboardingRequired = false
   124→    }
   125→
   126→    @UserDefault(key: "snapshotTimer") // 인증샷 기능을 위한 타이머
   127→    private var timerForSnapshot: TimerEntity?
   128→
   129→    var snapshotTimer: TimerEntity? {
   130→        return timerForSnapshot
   131→    }
   132→
   133→    func setSnapshotTimer(_ timer: TimerEntity) {
   134→        timerForSnapshot = timer
   135→    }
   136→}
   137→
   138→extension UserDefaultsClient: DependencyKey {
   139→    static let liveValue = UserDefaultsClient()
   140→}
   141→
   142→extension DependencyValues {
   143→    var userDefaults: UserDefaultsClient {
   144→        get { self[UserDefaultsClient.self] }
   145→        set { self[UserDefaultsClient.self] = newValue }
   146→    }
   147→}
   148→

