    34→    static let liveValue = TimerSettingManager()
    35→}
    36→
    37→extension DependencyValues {
    38→    var timerSettingManager: TimerSettingManager {
    39→        get { self[TimerSettingManager.self] }
    40→        set { self[TimerSettingManager.self] = newValue }
    41→    }
    42→}
